# to gen feed forward stream for lfsr 0,8 and 1,2 
def gen_lfsr_stream(n, mask, filter_val, ext_pos, seed):
    state = seed
    stream = vector(GF(_sage_const_2 ), _sage_const_640 )
    for i in range(_sage_const_640 ):
        idx = _sage_const_0 
        for j, p in enumerate(ext_pos):
            if (state >> p) & _sage_const_1 : idx |= (_sage_const_1  << j)
        stream[i] = (filter_val >> idx) & _sage_const_1 
        fb = bin(state & mask).count('1') & _sage_const_1 
        state = (state >> _sage_const_1 ) | (fb << (n - _sage_const_1 ))
    return stream




