extract = lambda x,b: sum(((int(x) >> p) & _sage_const_1 ) << i for i, p in enumerate(b))
blur = lambda x,i: (FILTERS[i] >> int(x)) & _sage_const_1 

class LFSR:
    def __init__(self, n, key, mask):
        self.n = n
        self.state = int(key) & ((_sage_const_1  << n) - _sage_const_1 )
        self.mask = int(mask)

    def __call__(self):
        b = self.state & _sage_const_1 
        fb = int(self.state & self.mask).bit_count() & _sage_const_1 
        self.state = (self.state >> _sage_const_1 ) | (fb << (self.n - _sage_const_1 ))
        return b

class Cipher:
    def __init__(self, s0, s1, s2, s8, seq63, seq255):
        self.lfsr0 = LFSR(Ns[_sage_const_0 ], s0, MASKS[_sage_const_0 ])
        self.lfsr1 = LFSR(Ns[_sage_const_1 ], s1, MASKS[_sage_const_1 ])
        self.lfsr2 = LFSR(Ns[_sage_const_2 ], s2, MASKS[_sage_const_2 ])
        self.lfsr8 = LFSR(Ns[_sage_const_8 ], s8, MASKS[_sage_const_8 ])
        
        self.seq63 = seq63
        self.seq255 = seq255
        self.clock = _sage_const_0 

    def bit(self):
        x = blur(extract(self.lfsr0.state, E0), _sage_const_0 )
        y = self.lfsr1.state & _sage_const_1 
        z = blur(extract(self.lfsr2.state, E2), _sage_const_1 )
        t = blur(extract(self.lfsr8.state, E8), _sage_const_7 )
        
        w_v = int(self.seq63[self.clock % _sage_const_63 ])
        u = int(self.seq255[self.clock % _sage_const_255 ])
        
        self.lfsr0()
        self.lfsr1()
        self.lfsr2()
        self.lfsr8()
        self.clock += _sage_const_1 
        
        return x ^ y ^ z ^ w_v ^ u ^ t

    def stream(self):
        while True:
            b = _sage_const_0 
            for i in reversed(range(_sage_const_8 )):
                b |= self.bit() << i
            yield b

    def decrypt(self, ct: bytes):
        return bytes([int(c) ^ int(k) for c, k in zip(ct, self.stream())])

